# Generated by Codex for Pyomo DoE benchmarking.
"""Generated by Codex for Pyomo DoE benchmarking.

Purpose:
    Execute a reproducible benchmark harness that compares central and greybox
    Pyomo DoE scripts using isolated subprocess runs. The harness discovers
    benchmark scripts, executes each script multiple times, captures timing and
    execution artifacts, and writes standardized tabular outputs.

Environments used:
    - Central scripts are executed using the configurable command provided by
      ``--central-python`` (default: ``pyomo``).
    - Greybox scripts are executed using the configurable command provided by
      ``--greybox-python`` (default: ``pyomogrey``).
    Each run is a fresh subprocess. No in-process imports are used.

Output structure:
    A top-level directory named ``data_greybox_benchmarking`` is created under
    the scripts root. It contains:
      - ``runs_all.csv``: one row per run
      - ``summary_by_script.csv``: aggregated per-script metrics
      - ``logs/<script_name>/run_XX_stdout.txt`` and
        ``logs/<script_name>/run_XX_stderr.txt``

Assumptions:
    - Benchmark scripts are located directly in ``--scripts-root``.
    - Greybox scripts follow ``*_greybox.py`` naming and there are exactly 4.
    - Central benchmark scripts are the matching counterparts of discovered
      greybox scripts (e.g., ``two_param_sin_central_greybox.py`` maps to
      ``two_param_sin_central.py``), resulting in exactly 4 central scripts.
    - Scripts may optionally print one line with:
      ``BENCHMETRICS: {"key": value, ...}``
      which is parsed and flattened into output columns.
"""

from __future__ import annotations

import argparse
import hashlib
import json
import os
import platform as platform_module
import re
import shlex
import shutil
import socket
import statistics
import subprocess
import time
import traceback
from datetime import datetime, timezone
from pathlib import Path
from typing import Any, Dict, Iterable, List, Optional, Sequence, Tuple

import pandas as pd

BENCHMETRICS_PATTERN = re.compile(r"^\\s*BENCHMETRICS:\\s*(\{.*\})\\s*$")
SEED_PATTERN = re.compile(
    r"(?i)\\b(?:random[_\\s-]?seed|seed)\\b\\s*[:=]\\s*([-+]?\\d+)",
)
IDAES_IPOPT_BIN = "/Users/snarasi2/.idaes/bin/ipopt"
IDAES_BIN_DIR = "/Users/snarasi2/.idaes/bin"


def parse_args() -> argparse.Namespace:
    """Parse command-line arguments for benchmark execution."""
    parser = argparse.ArgumentParser(
        description="Run greybox vs central benchmark harness with standardized outputs.",
    )
    parser.add_argument("--runs", type=int, default=10, help="Number of runs per script.")
    parser.add_argument(
        "--timeout",
        type=float,
        default=3600,
        help="Timeout in seconds per run. Use 0 to disable timeout.",
    )
    parser.add_argument(
        "--scripts-root",
        type=Path,
        default=Path.cwd(),
        help="Directory containing benchmark scripts.",
    )
    parser.add_argument(
        "--central-python",
        default="pyomo",
        help="Command used to execute central scripts.",
    )
    parser.add_argument(
        "--greybox-python",
        default="pyomogrey",
        help="Command used to execute greybox scripts.",
    )
    parser.add_argument(
        "--spyder-like",
        action="store_true",
        help="Run with full inherited environment (Spyder-like process context).",
    )
    parser.add_argument(
        "--force-ma57",
        action="store_true",
        help="Force IPOPT linear solver to MA57 via environment variable.",
    )
    parser.add_argument(
        "--force-idaes-ipopt",
        action="store_true",
        help="Force IPOPT_BIN_OVERRIDE to IDAES IPOPT path for every run.",
    )
    return parser.parse_args()


def sanitize_script_stem(script_path: Path) -> str:
    """Return a filesystem-safe script stem for directory naming."""
    return re.sub(r"[^A-Za-z0-9_.-]+", "_", script_path.stem)


def sha256_file(path: Path) -> str:
    """Compute and return SHA-256 hash for a script file."""
    hasher = hashlib.sha256()
    with path.open("rb") as handle:
        for chunk in iter(lambda: handle.read(1024 * 1024), b""):
            hasher.update(chunk)
    return hasher.hexdigest()


def _load_json_object(payload: str) -> Optional[Dict[str, Any]]:
    """Parse a JSON object string and return dict on success, else None."""
    try:
        obj = json.loads(payload)
    except json.JSONDecodeError:
        return None
    if isinstance(obj, dict):
        return obj
    return None


def flatten_dict(data: Dict[str, Any], prefix: str = "") -> Dict[str, Any]:
    """Flatten nested dictionaries into a single-level dict using dotted keys."""
    out: Dict[str, Any] = {}
    for key, value in data.items():
        full_key = f"{prefix}.{key}" if prefix else str(key)
        if isinstance(value, dict):
            out.update(flatten_dict(value, prefix=full_key))
        else:
            out[full_key] = value
    return out


def parse_benchmetrics(stdout: str, stderr: str) -> Dict[str, Any]:
    """Extract the latest BENCHMETRICS JSON line from run output and flatten it."""
    latest_obj: Optional[Dict[str, Any]] = None
    for line in (stdout + "\n" + stderr).splitlines():
        match = BENCHMETRICS_PATTERN.match(line)
        if not match:
            continue
        parsed = _load_json_object(match.group(1))
        if parsed is not None:
            latest_obj = parsed

    if latest_obj is None:
        return {}

    flattened = flatten_dict(latest_obj)
    return {f"metric_{key}": value for key, value in flattened.items()}


def parse_seed(stdout: str, stderr: str) -> Optional[str]:
    """Extract the last printed seed value from stdout/stderr if present."""
    latest_seed: Optional[str] = None
    for line in (stdout + "\n" + stderr).splitlines():
        match = SEED_PATTERN.search(line)
        if match:
            latest_seed = match.group(1)
    return latest_seed


def infer_mode_from_script(script_name: str) -> str:
    """Infer benchmark mode label from script filename."""
    if script_name.endswith("_greybox.py"):
        return "greybox"
    return "central"


def derive_central_from_greybox(greybox_script: Path, scripts_root: Path) -> Path:
    """Map a ``*_central_greybox.py`` script to its ``*_central.py`` counterpart."""
    stem = greybox_script.stem
    if not stem.endswith("_central_greybox"):
        raise ValueError(
            f"Greybox script does not follow expected '*_central_greybox.py' pattern: {greybox_script.name}"
        )
    base_prefix = stem[: -len("_central_greybox")]
    central_candidate = scripts_root / f"{base_prefix}_central.py"
    if not central_candidate.exists():
        raise FileNotFoundError(
            f"Missing central counterpart for {greybox_script.name}: expected {central_candidate.name}"
        )
    return central_candidate


def discover_scripts(scripts_root: Path) -> List[Path]:
    """Discover and validate the exact benchmark script set (4 central + 4 greybox)."""
    greybox_scripts = sorted(scripts_root.glob("*_greybox.py"))
    if len(greybox_scripts) != 4:
        found = [path.name for path in greybox_scripts]
        raise RuntimeError(
            "Expected exactly 4 greybox scripts matching '*_greybox.py' in scripts root "
            f"{scripts_root}, found {len(greybox_scripts)}: {found}"
        )

    central_scripts = sorted(derive_central_from_greybox(path, scripts_root) for path in greybox_scripts)
    unique_central = sorted(set(central_scripts))
    if len(unique_central) != 4:
        found = [path.name for path in unique_central]
        raise RuntimeError(
            "Expected exactly 4 unique central counterparts for discovered greybox scripts, "
            f"found {len(unique_central)}: {found}"
        )

    return unique_central + greybox_scripts


def resolve_base_command(execution_spec: str) -> List[str]:
    """Resolve execution spec into a base command list (without script path).

    Rules:
        - Single-token specs are treated as conda environment names:
          ``conda run -n <env> python``
        - Multi-token specs are treated as explicit command invocations.
    """
    parts = shlex.split(execution_spec)
    if not parts:
        raise ValueError("Execution command is empty.")
    if len(parts) == 1:
        if shutil.which("conda") is None:
            raise RuntimeError(
                "Conda is required to execute environment-based commands "
                f"('{execution_spec}') but 'conda' was not found on PATH."
            )
        return ["conda", "run", "-n", parts[0], "python"]
    return parts


def get_python_version(execution_spec: str) -> str:
    """Resolve interpreter version string for a configured execution spec."""
    try:
        cmd = resolve_base_command(execution_spec)
    except Exception:
        return ""
    try:
        result = subprocess.run(
            cmd + ["--version"],
            capture_output=True,
            text=True,
            timeout=30,
            check=False,
        )
    except Exception:
        return ""

    output = (result.stdout or "").strip() or (result.stderr or "").strip()
    return output


def build_clean_env(spyder_like: bool, force_ma57: bool, force_idaes_ipopt: bool) -> Dict[str, str]:
    """Build a minimal clean environment dictionary for fair subprocess runs.

    In spyder-like mode, inherit the full parent environment.
    """
    if spyder_like:
        env = os.environ.copy()
    else:
        keep_keys = {
            "PATH",
            "HOME",
            "USER",
            "LOGNAME",
            "SHELL",
            "TMPDIR",
            "TEMP",
            "TMP",
            "LANG",
            "LC_ALL",
            "LC_CTYPE",
            "TZ",
            "TERM",
        }
        if os.name == "nt":
            keep_keys.update({"SYSTEMROOT", "COMSPEC", "PATHEXT", "WINDIR"})
        env = {}
        for key in keep_keys:
            value = os.environ.get(key)
            if value is not None:
                env[key] = value

    if force_idaes_ipopt:
        env["IPOPT_BIN_OVERRIDE"] = IDAES_IPOPT_BIN
        current_path = env.get("PATH", "")
        path_parts = [part for part in current_path.split(os.pathsep) if part]
        path_parts = [part for part in path_parts if part != IDAES_BIN_DIR]
        env["PATH"] = os.pathsep.join([IDAES_BIN_DIR] + path_parts)

    if force_ma57:
        env["IPOPT_LINEAR_SOLVER"] = "ma57"

    return env


def compose_command(execution_spec: str, script_path: Path) -> List[str]:
    """Compose subprocess command list from configured execution spec.

    If the script declares a ``--wdir`` argument, append it to mirror common
    Spyder-style execution semantics used in this codebase.
    """
    cmd = resolve_base_command(execution_spec) + [str(script_path)]
    try:
        script_text = script_path.read_text(encoding="utf-8", errors="replace")
    except Exception:
        script_text = ""
    if "add_argument(\"--wdir\"" in script_text or "add_argument('--wdir'" in script_text:
        cmd.append("--wdir")
    return cmd


def write_text(path: Path, content: str) -> None:
    """Write UTF-8 text content to disk, creating parent directories if needed."""
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding="utf-8")


def run_one(
    script_path: Path,
    mode: str,
    run_index: int,
    timeout_s: float,
    executable_command: str,
    output_logs_dir: Path,
    script_hash: str,
    python_version_used: str,
    run_env: Dict[str, str],
) -> Dict[str, Any]:
    """Execute one script run and return standardized run metadata."""
    timestamp_utc = datetime.now(timezone.utc).isoformat()
    hostname = socket.gethostname()
    platform_name = platform_module.platform()
    command = compose_command(executable_command, script_path)

    stdout_text = ""
    stderr_text = ""
    return_code: Optional[int] = None
    status = "ok"

    start_monotonic = time.perf_counter()
    effective_timeout: Optional[float] = timeout_s if timeout_s > 0 else None
    try:
        result = subprocess.run(
            command,
            cwd=str(script_path.parent),
            capture_output=True,
            text=True,
            timeout=effective_timeout,
            check=False,
            env=run_env,
        )
        stdout_text = result.stdout or ""
        stderr_text = result.stderr or ""
        return_code = result.returncode
        if return_code != 0:
            status = "error"
    except subprocess.TimeoutExpired as exc:
        status = "timeout"
        return_code = 124
        stdout_text = (exc.stdout.decode("utf-8", errors="replace") if isinstance(exc.stdout, bytes) else exc.stdout) or ""
        stderr_text = (exc.stderr.decode("utf-8", errors="replace") if isinstance(exc.stderr, bytes) else exc.stderr) or ""
        stderr_text = f"{stderr_text}\n[HARNESS] TimeoutExpired after {timeout_s} seconds."
    except Exception:
        status = "error"
        return_code = 1
        stderr_text = traceback.format_exc()

    wall_time_s = max(0.0, time.perf_counter() - start_monotonic)

    script_log_dir = output_logs_dir / sanitize_script_stem(script_path)
    stdout_path = script_log_dir / f"run_{run_index:02d}_stdout.txt"
    stderr_path = script_log_dir / f"run_{run_index:02d}_stderr.txt"
    write_text(stdout_path, stdout_text)
    write_text(stderr_path, stderr_text)

    benchmetrics = parse_benchmetrics(stdout_text, stderr_text)
    seed_printed = parse_seed(stdout_text, stderr_text)

    row: Dict[str, Any] = {
        "timestamp_utc": timestamp_utc,
        "mode": mode,
        "script_name": script_path.name,
        "run_index": run_index,
        "environment_used": executable_command,
        "python_version_used": python_version_used,
        "hostname": hostname,
        "platform": platform_name,
        "wall_time_s": wall_time_s,
        "return_code": return_code,
        "status": status,
        "script_sha256": script_hash,
        "stdout_size_bytes": len(stdout_text.encode("utf-8", errors="replace")),
        "stderr_size_bytes": len(stderr_text.encode("utf-8", errors="replace")),
        "random_seed_printed": seed_printed,
        "stdout_log_file": str(stdout_path),
        "stderr_log_file": str(stderr_path),
    }
    row.update(benchmetrics)
    return row


def _safe_float(values: Iterable[Any]) -> List[float]:
    """Convert values to float list, omitting non-numeric entries."""
    out: List[float] = []
    for value in values:
        if value is None:
            continue
        if isinstance(value, bool):
            continue
        try:
            out.append(float(value))
        except (TypeError, ValueError):
            continue
    return out


def aggregate_summary(df: pd.DataFrame) -> pd.DataFrame:
    """Build per-script summary table from detailed run table."""
    if df.empty:
        return pd.DataFrame()

    metric_cols = [col for col in df.columns if col.startswith("metric_")]
    numeric_metric_cols: List[str] = []
    for col in metric_cols:
        numeric_series = pd.to_numeric(df[col], errors="coerce")
        if numeric_series.notna().any():
            numeric_metric_cols.append(col)

    summary_rows: List[Dict[str, Any]] = []
    for (mode, script_name), group in df.groupby(["mode", "script_name"], dropna=False):
        wall_times = pd.to_numeric(group["wall_time_s"], errors="coerce").dropna().tolist()
        return_codes = pd.to_numeric(group["return_code"], errors="coerce").dropna().tolist()

        row: Dict[str, Any] = {
            "mode": mode,
            "script_name": script_name,
            "runs": len(group),
            "mean_wall_time": statistics.fmean(wall_times) if wall_times else None,
            "median_wall_time": statistics.median(wall_times) if wall_times else None,
            "std_wall_time": statistics.stdev(wall_times) if len(wall_times) > 1 else 0.0,
            "min_wall_time": min(wall_times) if wall_times else None,
            "max_wall_time": max(wall_times) if wall_times else None,
            "success_rate": float((group["status"] == "ok").mean()) if len(group) else None,
            "mean_return_code": statistics.fmean(return_codes) if return_codes else None,
        }

        for metric_col in numeric_metric_cols:
            metric_vals = pd.to_numeric(group[metric_col], errors="coerce").dropna().tolist()
            row[f"mean_{metric_col}"] = statistics.fmean(metric_vals) if metric_vals else None

        summary_rows.append(row)

    return pd.DataFrame(summary_rows).sort_values(["mode", "script_name"]).reset_index(drop=True)


def run_benchmark(
    scripts: Sequence[Path],
    runs: int,
    timeout: float,
    central_python: str,
    greybox_python: str,
    output_dir: Path,
    spyder_like: bool,
    force_ma57: bool,
    force_idaes_ipopt: bool,
) -> Tuple[pd.DataFrame, pd.DataFrame]:
    """Execute full benchmark suite and return detailed and summary dataframes."""
    runs_all_rows: List[Dict[str, Any]] = []
    logs_dir = output_dir / "logs"

    pyver_cache = {
        "central": get_python_version(central_python),
        "greybox": get_python_version(greybox_python),
    }
    env_cache = {
        "central": build_clean_env(
            spyder_like=spyder_like,
            force_ma57=force_ma57,
            force_idaes_ipopt=force_idaes_ipopt,
        ),
        "greybox": build_clean_env(
            spyder_like=spyder_like,
            force_ma57=force_ma57,
            force_idaes_ipopt=force_idaes_ipopt,
        ),
    }

    for script_path in scripts:
        mode = infer_mode_from_script(script_path.name)
        exec_cmd = central_python if mode == "central" else greybox_python
        script_hash = sha256_file(script_path)

        for run_idx in range(1, runs + 1):
            row = run_one(
                script_path=script_path,
                mode=mode,
                run_index=run_idx,
                timeout_s=timeout,
                executable_command=exec_cmd,
                output_logs_dir=logs_dir,
                script_hash=script_hash,
                python_version_used=pyver_cache.get(mode, ""),
                run_env=env_cache[mode],
            )
            runs_all_rows.append(row)

    runs_df = pd.DataFrame(runs_all_rows)
    summary_df = aggregate_summary(runs_df)
    return runs_df, summary_df


def validate_cli_args(args: argparse.Namespace) -> None:
    """Validate benchmark CLI arguments before execution."""
    if args.runs <= 0:
        raise ValueError("--runs must be > 0")
    if args.timeout < 0:
        raise ValueError("--timeout must be >= 0 (0 disables timeout)")
    if not args.scripts_root.exists() or not args.scripts_root.is_dir():
        raise ValueError(f"--scripts-root is not a directory: {args.scripts_root}")


def main() -> int:
    """Run benchmark harness end-to-end and write required CSV/log outputs."""
    args = parse_args()
    validate_cli_args(args)

    scripts_root = args.scripts_root.resolve()
    scripts = discover_scripts(scripts_root)

    central_count = sum(1 for path in scripts if infer_mode_from_script(path.name) == "central")
    greybox_count = sum(1 for path in scripts if infer_mode_from_script(path.name) == "greybox")
    if central_count != 4 or greybox_count != 4:
        raise RuntimeError(
            f"Expected 4 central and 4 greybox scripts, got central={central_count}, greybox={greybox_count}."
        )

    output_dir = scripts_root / "data_greybox_benchmarking"
    output_dir.mkdir(parents=True, exist_ok=True)

    runs_df, summary_df = run_benchmark(
        scripts=scripts,
        runs=args.runs,
        timeout=args.timeout,
        central_python=args.central_python,
        greybox_python=args.greybox_python,
        output_dir=output_dir,
        spyder_like=args.spyder_like,
        force_ma57=args.force_ma57,
        force_idaes_ipopt=args.force_idaes_ipopt,
    )

    runs_csv_path = output_dir / "runs_all.csv"
    summary_csv_path = output_dir / "summary_by_script.csv"
    runs_df.to_csv(runs_csv_path, index=False)
    summary_df.to_csv(summary_csv_path, index=False)

    expected_runs = len(scripts) * args.runs
    actual_runs = len(runs_df)

    print(f"Scripts root: {scripts_root}")
    print(f"Discovered scripts: {len(scripts)} (central={central_count}, greybox={greybox_count})")
    for script in scripts:
        print(f"  - {script.name}")
    print(f"Expected total runs: {expected_runs}")
    print(f"Actual total runs: {actual_runs}")
    print(f"Wrote runs CSV: {runs_csv_path}")
    print(f"Wrote summary CSV: {summary_csv_path}")
    print(f"Logs directory: {output_dir / 'logs'}")

    return 0 if actual_runs == expected_runs else 1


if __name__ == "__main__":
    raise SystemExit(main())
